xpath.script:
(function() {
    function initLikert() {
        document.querySelectorAll('.tk_likert_options').forEach(function(group) {
            if (group.dataset.likertInit) return;
            group.dataset.likertInit = '1';

            var cards = group.querySelectorAll('.tk_likert_card');
            cards.forEach(function(card) {
                card.addEventListener('click', function(e) {

                    cards.forEach(function(c) {
                        c.classList.remove('tk_selected');
                    });
                    card.classList.add('tk_selected');

                    var radio = card.querySelector('.tk_likert_radio');
                    if (radio && !radio.checked) {
                        radio.checked = true;
                        // Hanya dispatch change, JANGAN dispatch click
                        radio.dispatchEvent(new Event('change', { bubbles: true }));

                        var nextBtn = document.querySelector('.o_survey_page_per_question button[value="next"], .o_survey_page_per_question button[value="finish"]');
                        if (nextBtn) {
                            nextBtn.disabled = false;
                            nextBtn.classList.remove('disabled');
                            nextBtn.classList.remove('tk_force_disabled');
                        }
                    }
                });
            });

            // Restore state
            cards.forEach(function(card) {
                var radio = card.querySelector('.tk_likert_radio');
                if (radio && radio.checked) {
                    card.classList.add('tk_selected');
                }
            });
        });
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', initLikert);
    } else {
        initLikert();
    }
})();

(function() {
    function disableContinueBtn() {
        // Cek apakah sudah ada jawaban terpilih
        var checked = document.querySelector('.tk_likert_radio:checked');
        if (checked) return; // sudah ada jawaban, biarkan aktif

        // Disable tombol Continue
        var nextBtn = document.querySelector('.o_survey_page_per_question button[value="next"], .o_survey_page_per_question button[value="finish"]');
        if (nextBtn) {
            nextBtn.classList.add('tk_force_disabled');
        }
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', disableContinueBtn);
    } else {
        disableContinueBtn();
    }
})();

(function() {
    function updateTkProgressBar() {
        var wrap = document.querySelector('.tk_progress_wrap');
        if (!wrap) return;

        var fill = wrap.querySelector('#tk_progress_fill');
        var currentEl = wrap.querySelector('#tk_current_q');
        var totalEl = wrap.querySelector('#tk_total_q');

        var total = parseInt(wrap.getAttribute('data-total') || (totalEl ? totalEl.textContent : '1'), 10) || 1;
        var current = parseInt(wrap.getAttribute('data-current') || (currentEl ? currentEl.textContent : '1'), 10) || 1;

        if (current < 1) current = 1;
        if (current > total) current = total;

        if (currentEl) currentEl.textContent = String(current);
        if (totalEl) totalEl.textContent = String(total);

        if (fill) {
            var pct = Math.round((current / total) * 100);
            fill.style.width = pct + '%';
        }
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', updateTkProgressBar);
    } else {
        updateTkProgressBar();
    }
})();

(function() {
    function injectBackButton() {
        var navCol = document.querySelector('.o_survey_page_per_question .col-12.text-center');
        if (!navCol) return;
        if (navCol.querySelector('.tk_btn_prev')) return;

        // Cek apakah ini bukan soal pertama
        var questionId = document.querySelector('input[name="question_id"]');
        if (!questionId) return;

        // Buat wrapper flex
        var wrapper = document.createElement('div');
        wrapper.className = 'tk_nav_actions';

        // Tombol back
        var leftDiv = document.createElement('div');
        leftDiv.className = 'tk_nav_left';

        // Cek apakah ada soal sebelumnya dari hidden input
        var form = document.querySelector('form');
        var allInputs = form ? form.querySelectorAll('input[type="hidden"]') : [];
        var hasPrev = false;

        // Soal pertama tidak punya previous — cek dari URL atau data
        // Cara mudah: kalau ada token di URL dan bukan soal 1
        var progressWrap = document.querySelector('.tk_progress_wrap');
        var currentQ = progressWrap ? parseInt(progressWrap.getAttribute('data-current') || '1') : 1;

        if (currentQ > 1) {
            hasPrev = true;
            var backBtn = document.createElement('button');
            backBtn.type = 'submit';
            backBtn.name = 'button_submit';
            backBtn.value = 'previous';
            backBtn.className = 'btn tk_btn_prev';
            backBtn.innerHTML = '← Sebelumnya';
            leftDiv.appendChild(backBtn);
        }

        // Pindahkan tombol existing ke kanan
        var rightDiv = document.createElement('div');
        rightDiv.className = 'tk_nav_right';

        // Ambil semua child navCol dan pindah ke rightDiv
        while (navCol.firstChild) {
            rightDiv.appendChild(navCol.firstChild);
        }

        wrapper.appendChild(leftDiv);
        wrapper.appendChild(rightDiv);
        navCol.appendChild(wrapper);
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', injectBackButton);
    } else {
        injectBackButton();
    }
})();
